export default "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>Member Manager</title>\n    <style>\n        *,*::before,*::after{margin:0;padding:0;box-sizing:border-box}\n        :root{\n            --bg-0:#0b0c10;--bg-1:#111419;--bg-2:#1a1d24;--bg-3:#23272f;--bg-4:#2c313b;\n            --bd:#2a2e38;--bd-h:#3a3f4c;\n            --t1:#e4e6eb;--t2:#9a9da8;--t3:#5e616d;\n            --acc:#6366f1;--acc-h:#818cf8;--acc-bg:rgba(99,102,241,.1);--acc-bd:rgba(99,102,241,.3);\n            --grn:#34d399;--grn-bg:rgba(34,211,153,.08);--grn-bd:rgba(34,211,153,.25);\n            --red:#f87171;--red-bg:rgba(248,113,113,.08);--red-bd:rgba(248,113,113,.25);\n            --amb:#fbbf24;--amb-bg:rgba(251,191,36,.08);--amb-bd:rgba(251,191,36,.25);\n            --gold:#fbbf24;--silver:#94a3b8;--bronze:#d97706;--copper:#e57c5b;--steel:#64748b;\n            --font:-apple-system,BlinkMacSystemFont,\"Segoe UI\",system-ui,sans-serif;\n            --mono:ui-monospace,\"SF Mono\",\"Cascadia Code\",Consolas,monospace;\n            --r:6px;--rl:10px\n        }\n        body{font-family:var(--font);background:var(--bg-0);color:var(--t1);line-height:1.5;min-height:100vh}\n        body.no-scroll{overflow:hidden}\n        body::before{content:'';position:fixed;top:0;left:0;right:0;height:2px;background:linear-gradient(90deg,transparent,var(--acc),var(--acc-h),var(--acc),transparent);z-index:10000}\n        ::-webkit-scrollbar{width:6px;height:6px}::-webkit-scrollbar-track{background:transparent}::-webkit-scrollbar-thumb{background:var(--bg-4);border-radius:3px}\n\n        #setup{display:flex;flex-direction:column;align-items:center;justify-content:center;min-height:100vh;padding:24px;gap:20px}\n        #setup h1{font-size:28px;font-weight:800;letter-spacing:-.04em}\n        #setup h1 .ac{color:var(--acc-h)}\n        #setup>p{color:var(--t3);font-size:14px;text-align:center;max-width:400px}\n        .setup-row{display:flex;gap:16px;width:100%;max-width:500px}\n        .setup-card{flex:1;background:var(--bg-2);border:1px solid var(--bd);border-radius:var(--rl);padding:20px;transition:border-color .2s}\n        .setup-card.done{border-color:var(--grn-bd)}\n        .setup-card-title{font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:.05em;color:var(--t3);margin-bottom:12px}\n        .setup-status{font-size:13px;color:var(--t3);margin-bottom:12px;display:flex;align-items:center;gap:8px}\n        .setup-status.ok{color:var(--grn)}\n        .setup-status .dot{width:8px;height:8px;border-radius:50%;background:var(--t3)}\n        .setup-status.ok .dot{background:var(--grn)}\n        .setup-btns{display:flex;gap:8px}\n        .setup-card.done .setup-btns{display:none}\n        .setup-err{color:var(--red);font-size:12px;text-align:center;max-width:400px;display:none}\n\n        .header{display:flex;align-items:center;justify-content:space-between;padding:12px 24px;background:var(--bg-1);border-bottom:1px solid var(--bd);position:sticky;top:2px;z-index:100}\n        .header-left{display:flex;align-items:center;gap:14px}\n        .header h1{font-size:16px;font-weight:700;letter-spacing:-.03em}\n        .header h1 .ac{color:var(--acc-h)}\n        .file-badges{display:flex;gap:6px}\n        .fb{display:inline-flex;align-items:center;gap:5px;padding:2px 9px;border-radius:16px;font-size:11px;font-family:var(--mono);font-weight:500;color:var(--grn);border:1px solid var(--grn-bd);background:var(--grn-bg)}\n        .fb::before{content:'';width:5px;height:5px;border-radius:50%;background:var(--grn)}\n        .header-right{display:flex;align-items:center;gap:6px}\n\n        .btn{display:inline-flex;align-items:center;gap:6px;padding:7px 14px;font-family:var(--font);font-size:13px;font-weight:500;border:1px solid var(--bd);border-radius:var(--r);cursor:pointer;transition:all 120ms;white-space:nowrap;background:var(--bg-2);color:var(--t2)}\n        .btn:hover{background:var(--bg-3);color:var(--t1);border-color:var(--bd-h)}.btn:active{transform:scale(.97)}\n        .btn-p{background:var(--acc);border-color:var(--acc);color:#fff}.btn-p:hover{background:var(--acc-h);border-color:var(--acc-h)}\n        .btn-d{color:var(--red);border-color:var(--red-bd);background:var(--red-bg)}.btn-d:hover{background:rgba(248,113,113,.16);border-color:var(--red)}\n        .btn-sm{padding:4px 10px;font-size:12px}\n\n        .toolbar{display:flex;align-items:center;gap:14px;padding:12px 24px;background:var(--bg-1);border-bottom:1px solid var(--bd)}\n        .search-wrap{position:relative;flex:1;max-width:320px}\n        .search-wrap svg{position:absolute;left:10px;top:50%;transform:translateY(-50%);width:15px;height:15px;color:var(--t3);pointer-events:none}\n        .search-input{width:100%;padding:7px 12px 7px 32px;font-family:var(--font);font-size:13px;background:var(--bg-0);border:1px solid var(--bd);border-radius:var(--r);color:var(--t1);outline:none;transition:border-color 150ms,box-shadow 150ms}\n        .search-input::placeholder{color:var(--t3)}.search-input:focus{border-color:var(--acc);box-shadow:0 0 0 2px var(--acc-bg)}\n        .stats{font-size:12px;color:var(--t3);font-variant-numeric:tabular-nums}.stats b{color:var(--t2);font-weight:600}\n\n        .table-wrap{margin:16px 24px 24px;border:1px solid var(--bd);border-radius:var(--rl);overflow:hidden}\n        .table-scroll{overflow-x:auto}\n        .data-table{width:100%;border-collapse:collapse;font-size:13px}\n        .data-table thead th{background:var(--bg-2);padding:10px 14px;text-align:left;font-weight:600;font-size:11px;text-transform:uppercase;letter-spacing:.05em;color:var(--t3);border-bottom:1px solid var(--bd);cursor:pointer;user-select:none;white-space:nowrap;transition:color 120ms}\n        .data-table thead th:hover{color:var(--t2)}\n        .data-table thead th.sorted{color:var(--acc-h)}\n        .data-table thead th:last-child{cursor:default}\n        .si{display:inline-block;margin-left:3px;font-size:10px;opacity:0;transition:opacity 120ms}\n        th:hover .si,th.sorted .si{opacity:1}\n        .data-table tbody tr{border-bottom:1px solid var(--bd);transition:background 100ms;border-left:3px solid transparent;cursor:pointer}\n        .data-table tbody tr:last-child{border-bottom:none}\n        .data-table tbody tr:hover{background:var(--bg-2);border-left-color:var(--acc)}\n        .data-table tbody td{padding:10px 14px;color:var(--t2);white-space:nowrap}\n        .cell-id{font-family:var(--mono);font-size:11px;color:var(--t3)}\n        .copy-btn{background:none;border:1px solid var(--bd);color:var(--t3);cursor:pointer;font-size:11px;padding:1px 5px;border-radius:3px;transition:all 120ms;vertical-align:middle;line-height:1}\n        .copy-btn:hover{color:var(--acc-h);border-color:var(--acc-bd);background:var(--acc-bg)}\n        .cell-name{color:var(--t1);font-weight:500}\n        .cell-actions{text-align:right;white-space:nowrap}\n        .cell-actions .btn{opacity:0;transition:opacity 120ms,background 120ms}\n        .data-table tbody tr:hover .cell-actions .btn{opacity:1}\n        .cell-urgent{color:var(--red);font-weight:600}\n\n        .tier{display:inline-block;padding:2px 10px;font-size:11px;font-weight:700;border-radius:20px;letter-spacing:.03em;text-transform:uppercase}\n        .tier-gold{color:var(--gold);background:rgba(251,191,36,.1);border:1px solid rgba(251,191,36,.25)}\n        .tier-silver{color:var(--silver);background:rgba(148,163,184,.1);border:1px solid rgba(148,163,184,.2)}\n        .tier-bronze{color:var(--bronze);background:rgba(217,119,6,.1);border:1px solid rgba(217,119,6,.25)}\n        .tier-copper{color:var(--copper);background:rgba(229,124,91,.1);border:1px solid rgba(229,124,91,.25)}\n        .tier-steel{color:var(--steel);background:rgba(100,116,139,.1);border:1px solid rgba(100,116,139,.2)}\n\n        .nc{min-width:28px;height:26px;border-radius:13px;display:inline-flex;align-items:center;justify-content:center;gap:4px;font-size:11px;font-weight:600;cursor:pointer;border:1px solid var(--bd);background:var(--bg-3);color:var(--t3);transition:all 120ms;padding:0 8px}\n        .nc:hover{border-color:var(--bd-h);color:var(--t2)}.nc.has{color:var(--acc-h);border-color:var(--acc-bd);background:var(--acc-bg)}\n\n        .empty-state{text-align:center;padding:60px 20px;display:none}\n        .empty-icon{width:56px;height:56px;margin:0 auto 16px;border:2px dashed var(--bd);border-radius:14px;display:flex;align-items:center;justify-content:center;color:var(--t3);font-size:22px}\n        .empty-state h3{font-size:15px;font-weight:600;color:var(--t2);margin-bottom:4px}\n        .empty-state p{font-size:13px;color:var(--t3);max-width:280px;margin:0 auto}\n\n        .mo{display:none;position:fixed;inset:0;background:rgba(0,0,0,.55);backdrop-filter:blur(6px);z-index:1000;align-items:center;justify-content:center}\n        .mo.open{display:flex}\n        .modal{background:var(--bg-2);border:1px solid var(--bd);border-radius:var(--rl);width:94%;max-width:520px;animation:mIn 180ms ease;box-shadow:0 20px 60px rgba(0,0,0,.5)}\n        .modal-sm{max-width:400px}\n        @keyframes mIn{from{opacity:0;transform:translateY(8px) scale(.98)}to{opacity:1;transform:translateY(0) scale(1)}}\n        .mh{display:flex;align-items:center;justify-content:space-between;padding:16px 22px;border-bottom:1px solid var(--bd)}\n        .mh h2{font-size:15px;font-weight:700}.mh .sub{font-size:12px;color:var(--t3);margin-left:8px;font-weight:400}\n        .mx{background:none;border:none;color:var(--t3);font-size:20px;cursor:pointer;padding:2px 6px;line-height:1;border-radius:4px;transition:all 120ms}.mx:hover{color:var(--t1);background:var(--bg-4)}\n        .mb{padding:22px}\n        .mf{display:flex;justify-content:flex-end;gap:8px;padding:14px 22px;border-top:1px solid var(--bd)}\n\n        .modal-notes{max-width:900px;width:900px;height:80vh;max-height:720px;display:flex;flex-direction:column;overflow:hidden}\n        .modal-notes .mh{flex-shrink:0}\n        .notes-body{flex:1;display:flex;overflow:hidden}\n        .notes-left{width:320px;flex-shrink:0;display:flex;flex-direction:column;border-right:1px solid var(--bd);padding:18px;gap:10px}\n        .notes-left label{font-size:11px;font-weight:600;color:var(--t3);text-transform:uppercase;letter-spacing:.04em}\n        .notes-ta{width:100%;flex:1;min-height:120px;padding:10px 12px;font-family:var(--font);font-size:13px;line-height:1.6;background:var(--bg-0);border:1px solid var(--bd);border-radius:var(--r);color:var(--t1);outline:none;resize:none;transition:border-color 150ms,box-shadow 150ms}\n        .notes-ta:focus{border-color:var(--acc);box-shadow:0 0 0 2px var(--acc-bg)}\n        .notes-ta::placeholder{color:var(--t3)}\n        .notes-right{flex:1;display:flex;flex-direction:column;overflow:hidden}\n        .notes-right-header{padding:14px 18px;border-bottom:1px solid var(--bd);font-size:11px;font-weight:600;color:var(--t3);text-transform:uppercase;letter-spacing:.04em;flex-shrink:0}\n        .notes-list{flex:1;overflow-y:auto;padding:10px}\n        .note-card{background:var(--bg-1);border:1px solid var(--bd);border-radius:var(--r);margin-bottom:8px;max-height:140px;display:flex;flex-direction:column;overflow:hidden}\n        .note-card:last-child{margin-bottom:0}\n        .note-head{display:flex;justify-content:space-between;align-items:center;padding:10px 14px;flex-shrink:0;border-bottom:1px solid var(--bd);background:var(--bg-1)}\n        .note-text-wrap{flex:1;overflow-y:auto;padding:10px 14px}\n        .note-time{font-size:10px;color:var(--t3);font-family:var(--mono)}\n        .note-edit{background:none;border:none;color:var(--t3);cursor:pointer;font-size:13px;padding:0 4px;transition:color 120ms;line-height:1}.note-edit:hover{color:var(--acc-h)}\n        .note-del{background:none;border:none;color:var(--t3);cursor:pointer;font-size:14px;padding:0 4px;transition:color 120ms;line-height:1}.note-del:hover{color:var(--red)}\n        .note-edit-ta{width:100%;height:100%;padding:8px;font-family:var(--font);font-size:12px;line-height:1.6;background:var(--bg-0);border:none;border-radius:0;color:var(--t1);outline:none;resize:none}\n        .note-text{font-size:12px;line-height:1.6;color:var(--t2);white-space:pre-wrap;word-wrap:break-word}\n        .notes-empty{text-align:center;padding:40px 20px;color:var(--t3);font-size:13px}\n        .note-info{font-size:13px;color:var(--t2);padding:12px 18px;border-bottom:1px solid var(--bd);display:flex;justify-content:space-between;align-items:center;flex-shrink:0;background:var(--bg-3)}\n        .note-info strong{color:var(--t1)}.note-info .nid{font-family:var(--mono);font-size:11px;color:var(--t3)}\n        .note-fields{display:flex;gap:12px;padding:10px 18px;border-bottom:1px solid var(--bd);flex-shrink:0;align-items:center}\n        .note-fields label{font-size:10px;font-weight:600;color:var(--t3);text-transform:uppercase;letter-spacing:.04em;margin-right:4px}\n        .note-fields select,.note-fields input{padding:5px 8px;font-family:var(--font);font-size:12px;background:var(--bg-0);border:1px solid var(--bd);border-radius:var(--r);color:var(--t1);outline:none;transition:border-color 150ms}\n        .note-fields select:focus,.note-fields input:focus{border-color:var(--acc)}\n        .note-fields select{cursor:pointer}\n        .nf-group{display:flex;align-items:center;gap:4px}\n        .drop-zone{border:2px dashed var(--bd);border-radius:var(--rl);padding:30px 20px;text-align:center;cursor:pointer;transition:all .2s;background:var(--bg-1);width:100%;max-width:500px}\n        .drop-zone:hover,.drop-zone.over{border-color:var(--acc);background:var(--acc-bg)}\n        .drop-text{font-size:14px;font-weight:600;color:var(--t1);margin-bottom:4px}\n        .drop-sub{font-size:12px;color:var(--t3)}\n\n        .fg{display:grid;grid-template-columns:1fr 1fr;gap:14px}\n        .fi{display:flex;flex-direction:column;gap:4px}.fi.span{grid-column:1/-1}\n        .fi label{font-size:11px;font-weight:600;color:var(--t3);text-transform:uppercase;letter-spacing:.04em}\n        .fi input,.fi select{padding:8px 11px;font-family:var(--font);font-size:13px;background:var(--bg-0);border:1px solid var(--bd);border-radius:var(--r);color:var(--t1);outline:none;transition:border-color 150ms,box-shadow 150ms}\n        .fi input:focus,.fi select:focus{border-color:var(--acc);box-shadow:0 0 0 2px var(--acc-bg)}\n        .fi select{cursor:pointer}\n\n        #toasts{position:fixed;bottom:14px;right:14px;z-index:10001;display:flex;flex-direction:column-reverse;gap:6px;pointer-events:none}\n        .toast{padding:9px 16px;font-size:13px;font-weight:500;border-radius:var(--r);animation:tIn 180ms ease;box-shadow:0 8px 30px rgba(0,0,0,.35);pointer-events:auto}\n        .toast-success{border:1px solid var(--grn-bd);background:var(--grn-bg);color:var(--grn)}\n        .toast-danger{border:1px solid var(--red-bd);background:var(--red-bg);color:var(--red)}\n        .toast-info{border:1px solid var(--acc-bd);background:var(--acc-bg);color:var(--acc-h)}\n        .toast.out{animation:tOut 180ms ease forwards}\n        @keyframes tIn{from{opacity:0;transform:translateX(30px)}to{opacity:1;transform:translateX(0)}}\n        @keyframes tOut{from{opacity:1;transform:translateX(0)}to{opacity:0;transform:translateX(30px)}}\n\n        .fchip{display:inline-flex;align-items:center;gap:4px;padding:4px 10px;font-size:11px;border-radius:4px;cursor:pointer;border:1px solid var(--bd);background:var(--bg-2);color:var(--t3);transition:all 120ms;user-select:none}\n        .fchip:hover{border-color:var(--bd-h);color:var(--t2)}\n        .fchip.on{background:var(--acc-bg);border-color:var(--acc-bd);color:var(--acc-h)}\n        .fchip input{display:none}\n        .filter-row{border:1px solid var(--bd);border-radius:var(--r);padding:10px;margin-bottom:8px;background:var(--bg-0)}\n        .filter-row:last-child{margin-bottom:0}\n        .filter-header{display:flex;align-items:center;gap:8px;margin-bottom:8px}\n        .filter-header select{flex:1;padding:5px 8px;font-family:var(--font);font-size:12px;background:var(--bg-2);border:1px solid var(--bd);border-radius:var(--r);color:var(--t1);cursor:pointer}\n        .filter-remove{background:none;border:none;color:var(--t3);cursor:pointer;font-size:16px;line-height:1;transition:color 120ms}.filter-remove:hover{color:var(--red)}\n        .filter-chips{display:flex;flex-wrap:wrap;gap:5px;max-height:100px;overflow-y:auto}\n        #app{display:none}\n    </style>\n</head>\n<body>\n\n<!-- SETUP -->\n<div id=\"setup\">\n    <h1>Member<span class=\"ac\">Manager</span></h1>\n    <p>Open both CSV files to get started. If first time, create new files.</p>\n    <div class=\"setup-row\">\n        <div class=\"setup-card\" id=\"setupM\">\n            <div class=\"setup-card-title\">Members File</div>\n            <div class=\"setup-status\" id=\"setupMStatus\"><span class=\"dot\"></span> Not loaded</div>\n            <div class=\"setup-btns\">\n                <button class=\"btn btn-p\" onclick=\"App.openMemberFile()\">Open</button>\n                <button class=\"btn\" onclick=\"App.createMemberFile()\">New</button>\n            </div>\n        </div>\n        <div class=\"setup-card\" id=\"setupN\">\n            <div class=\"setup-card-title\">Notes File</div>\n            <div class=\"setup-status\" id=\"setupNStatus\"><span class=\"dot\"></span> Not loaded</div>\n            <div class=\"setup-btns\">\n                <button class=\"btn btn-p\" onclick=\"App.openNoteFile()\">Open</button>\n                <button class=\"btn\" onclick=\"App.createNoteFile()\">New</button>\n            </div>\n        </div>\n    </div>\n    <div style=\"color:var(--t3);font-size:13px;font-weight:600\">or</div>\n    <div class=\"drop-zone\" id=\"dropZone\">\n        <div class=\"drop-text\">Drag &amp; drop both CSV files here</div>\n        <div class=\"drop-sub\" id=\"dropStatus\">members + notes</div>\n    </div>\n    <div class=\"setup-err\" id=\"setupErr\"></div>\n</div>\n\n<!-- APP -->\n<div id=\"app\">\n    <header class=\"header\">\n        <div class=\"header-left\">\n            <h1>Member<span class=\"ac\">Manager</span></h1>\n            <div class=\"file-badges\"><span class=\"fb\" id=\"badgeM\"></span><span class=\"fb\" id=\"badgeN\"></span></div>\n        </div>\n        <div class=\"header-right\">\n            <button class=\"btn\" onclick=\"document.getElementById('importFile').click()\">Import CSV</button>\n            <button class=\"btn btn-p\" onclick=\"App.showMemberModal()\">+ Add Member</button>\n        </div>\n        <input type=\"file\" id=\"importFile\" accept=\".csv\" style=\"display:none\" onchange=\"App.handleImportFile(this)\">\n    </header>\n    <div class=\"toolbar\">\n        <div class=\"search-wrap\">\n            <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><circle cx=\"11\" cy=\"11\" r=\"8\"/><line x1=\"21\" y1=\"21\" x2=\"16.65\" y2=\"16.65\"/></svg>\n            <input type=\"text\" class=\"search-input\" id=\"searchInput\" placeholder=\"Search members...\" oninput=\"App.onSearch(this.value)\">\n        </div>\n        <div class=\"stats\" id=\"stats\"></div>\n    </div>\n    <div class=\"table-wrap\"><div class=\"table-scroll\">\n        <table class=\"data-table\" id=\"dataTable\"><thead><tr>\n            <th data-col=\"memberId\" onclick=\"App.sort('memberId')\">Member ID <span class=\"si\"></span></th>\n            <th data-col=\"name\" onclick=\"App.sort('name')\">Member Name <span class=\"si\"></span></th>\n            <th data-col=\"tier\" onclick=\"App.sort('tier')\">Tier <span class=\"si\"></span></th>\n            <th data-col=\"nextCall\" onclick=\"App.sort('nextCall')\">Next Call <span class=\"si\"></span></th>\n            <th data-col=\"callType\" onclick=\"App.sort('callType')\">Call Type <span class=\"si\"></span></th>\n            <th data-col=\"cm\" onclick=\"App.sort('cm')\">CM <span class=\"si\"></span></th>\n            <th>Notes</th><th></th>\n        </tr></thead><tbody id=\"tbody\"></tbody></table>\n    </div>\n    <div class=\"empty-state\" id=\"emptyState\"><div class=\"empty-icon\">+</div><h3>No members yet</h3><p>Click \"+ Add Member\" to get started.</p></div>\n    </div>\n</div>\n\n<!-- MEMBER MODAL -->\n<div class=\"mo\" id=\"memberModal\" onclick=\"if(event.target===this)App.hideMemberModal()\">\n    <div class=\"modal\"><div class=\"mh\"><h2 id=\"mmTitle\">Add Member</h2><button class=\"mx\" onclick=\"App.hideMemberModal()\">&times;</button></div>\n    <div class=\"mb\"><form id=\"mForm\" class=\"fg\" onsubmit=\"return App.submitMember(event)\">\n        <div class=\"fi\"><label>Member ID *</label><input type=\"text\" id=\"fMemberId\" required placeholder=\"e.g. H12345678\"></div>\n        <div class=\"fi\"><label>Member Name *</label><input type=\"text\" id=\"fName\" required></div>\n        <div class=\"fi\"><label>Metal Tier</label><select id=\"fTier\"><option value=\"\">Select...</option><option>Gold</option><option>Silver</option><option>Bronze</option><option>Copper</option><option>Steel</option></select></div>\n        <div class=\"fi\"><label>Call Type *</label><select id=\"fCallType\" required><option value=\"\">Select...</option><option>Urgent</option><option>TOC x1</option><option>TOC x2</option><option>TOC x3</option><option>TOC F/U</option><option>ICP x1</option><option>ICP x2</option><option>ICP x3</option><option>HRA x1</option><option>HRA x2</option><option>HRA x3</option><option>ICP HRA</option></select></div>\n        <div class=\"fi\"><label>CM</label><input type=\"text\" id=\"fCM\" placeholder=\"Care Manager\"></div>\n        <div class=\"fi\"><label>Next Call Date</label><input type=\"date\" id=\"fNextCall\"></div>\n        <button type=\"submit\" style=\"display:none\">Submit</button>\n    </form></div>\n    <div class=\"mf\"><button class=\"btn\" onclick=\"App.hideMemberModal()\">Cancel</button><button class=\"btn btn-p\" onclick=\"document.getElementById('mForm').requestSubmit()\">Save Member</button></div>\n    </div>\n</div>\n\n<!-- NOTES MODAL -->\n<div class=\"mo\" id=\"notesModal\" onclick=\"if(event.target===this)App.hideNotesModal()\">\n    <div class=\"modal modal-notes\">\n        <div class=\"mh\"><h2>Notes<span class=\"sub\" id=\"notesSub\"></span></h2><button class=\"mx\" onclick=\"App.hideNotesModal()\">&times;</button></div>\n        <div class=\"note-info\" id=\"noteInfo\"></div>\n        <div class=\"note-fields\" id=\"noteFields\"></div>\n        <div class=\"notes-body\">\n            <div class=\"notes-left\">\n                <label>New Note</label>\n                <textarea class=\"notes-ta\" id=\"noteInput\" placeholder=\"Type a new note...\"></textarea>\n                <button class=\"btn btn-p\" style=\"align-self:center\" onclick=\"App.addNote()\">Add Note</button>\n            </div>\n            <div class=\"notes-right\">\n                <div class=\"notes-right-header\">Note History</div>\n                <div class=\"notes-list\" id=\"notesList\"></div>\n            </div>\n        </div>\n    </div>\n</div>\n\n<!-- DELETE MODAL -->\n<div class=\"mo\" id=\"deleteModal\" onclick=\"if(event.target===this)App.hideDeleteModal()\">\n    <div class=\"modal modal-sm\"><div class=\"mh\"><h2>Delete Member</h2><button class=\"mx\" onclick=\"App.hideDeleteModal()\">&times;</button></div>\n    <div class=\"mb\"><p style=\"color:var(--t2)\">Delete <strong id=\"delName\"></strong> and all their notes?</p></div>\n    <div class=\"mf\"><button class=\"btn\" onclick=\"App.hideDeleteModal()\">Cancel</button><button class=\"btn btn-d\" onclick=\"App.confirmDelete()\">Delete</button></div>\n    </div>\n</div>\n\n<!-- IMPORT MODAL -->\n<div class=\"mo\" id=\"importModal\" onclick=\"if(event.target===this)App.hideImportModal()\">\n    <div class=\"modal\" style=\"max-width:600px\">\n        <div class=\"mh\"><h2>Import CSV</h2><button class=\"mx\" onclick=\"App.hideImportModal()\">&times;</button></div>\n        <div class=\"mb\">\n            <p style=\"color:var(--t2);font-size:13px;margin-bottom:14px\">Map your CSV columns to member fields. Unmapped fields use defaults.</p>\n            <div id=\"importMappings\" class=\"fg\" style=\"margin-bottom:16px\"></div>\n            <div style=\"border:1px solid var(--bd);border-radius:var(--r);padding:14px;margin-bottom:16px;background:var(--bg-1)\">\n                <div style=\"display:flex;align-items:center;justify-content:space-between;margin-bottom:10px\">\n                    <label style=\"font-size:11px;font-weight:600;color:var(--t3);text-transform:uppercase;letter-spacing:.04em\">Filters</label>\n                    <button class=\"btn btn-sm\" onclick=\"App.addImportFilter()\">+ Add Filter</button>\n                </div>\n                <div id=\"importFilters\"></div>\n            </div>\n            <div class=\"fg\">\n                <div class=\"fi\"><label>Default Call Type *</label>\n                    <select id=\"importCallType\"><option value=\"\">Select...</option><option>Urgent</option><option>TOC x1</option><option>TOC x2</option><option>TOC x3</option><option>TOC F/U</option><option>ICP x1</option><option>ICP x2</option><option>ICP x3</option><option>HRA x1</option><option>HRA x2</option><option>HRA x3</option><option>ICP HRA</option></select>\n                </div>\n                <div class=\"fi\"><label>Default Next Call</label>\n                    <input type=\"date\" id=\"importNextCall\">\n                </div>\n            </div>\n            <div id=\"importPreview\" style=\"margin-top:14px;font-size:12px;color:var(--t3)\"></div>\n        </div>\n        <div class=\"mf\"><button class=\"btn\" onclick=\"App.hideImportModal()\">Cancel</button><button class=\"btn btn-p\" onclick=\"App.runImport()\">Import Members</button></div>\n    </div>\n</div>\n\n<div id=\"toasts\"></div>\n\n<script>\nvar CALL_TYPES=['Urgent','TOC x1','TOC x2','TOC x3','TOC F/U','ICP x1','ICP x2','ICP x3','HRA x1','HRA x2','HRA x3','ICP HRA'];\nvar CP={};CALL_TYPES.forEach(function(t,i){CP[t]=i});\nvar TIER_ORDER={Gold:0,Silver:1,Bronze:2,Copper:3,Steel:4};\n\nfunction parseCSV(text){\n    var rows=[],row=[],f='',q=false,i=0;\n    while(i<text.length){var c=text[i];\n        if(q){if(c==='\"'){if(i+1<text.length&&text[i+1]==='\"'){f+='\"';i+=2}else{q=false;i++}}else{f+=c;i++}}\n        else{if(c==='\"'){q=true;i++}else if(c===','){row.push(f);f='';i++}else if(c==='\\r'){i++}else if(c==='\\n'){row.push(f);f='';if(row.length>1||row.some(function(x){return x.trim()}))rows.push(row);row=[];i++}else{f+=c;i++}}\n    }\n    row.push(f);if(row.length>1||row.some(function(x){return x.trim()}))rows.push(row);\n    return rows;\n}\nfunction csvF(v){v=String(v==null?'':v);return(v.indexOf(',')>-1||v.indexOf('\"')>-1||v.indexOf('\\n')>-1||v.indexOf('\\r')>-1)?'\"'+v.replace(/\"/g,'\"\"')+'\"':v}\n\nvar App={\n    members:[],notes:[],nextMid:1,nextNid:1,\n    mHandle:null,nHandle:null,mFile:'',nFile:'',\n    query:'',sortCol:'default',sortDir:'asc',manualSort:false,\n    editId:null,delId:null,notesForId:null,\n\n    init:function(){this.bindKeys();this.bindDrop()},\n\n    /* ===== FILE OPERATIONS (File System Access API) ===== */\n    openMemberFile:function(){\n        var self=this;\n        window.showOpenFilePicker({types:[{description:'CSV',accept:{'text/csv':['.csv']}}]}).then(function(handles){\n            self.mHandle=handles[0];\n            return self.mHandle.getFile();\n        }).then(function(file){\n            self.mFile=file.name;\n            return file.text();\n        }).then(function(text){\n            self.parseMemberCSV(text);\n            self.checkReady();\n        }).catch(function(e){if(e.name!=='AbortError')self.showErr(e.message)});\n    },\n\n    openNoteFile:function(){\n        var self=this;\n        window.showOpenFilePicker({types:[{description:'CSV',accept:{'text/csv':['.csv']}}]}).then(function(handles){\n            self.nHandle=handles[0];\n            return self.nHandle.getFile();\n        }).then(function(file){\n            self.nFile=file.name;\n            return file.text();\n        }).then(function(text){\n            self.parseNoteCSV(text);\n            self.checkReady();\n        }).catch(function(e){if(e.name!=='AbortError')self.showErr(e.message)});\n    },\n\n    createMemberFile:function(){\n        var self=this;\n        window.showSaveFilePicker({suggestedName:'members.csv',types:[{description:'CSV',accept:{'text/csv':['.csv']}}]}).then(function(handle){\n            self.mHandle=handle;self.mFile=handle.name;\n            self.members=[];self.nextMid=1;\n            return self.writeMemberCSV();\n        }).then(function(){\n            self.checkReady();\n        }).catch(function(e){if(e.name!=='AbortError')self.showErr(e.message)});\n    },\n\n    createNoteFile:function(){\n        var self=this;\n        window.showSaveFilePicker({suggestedName:'notes.csv',types:[{description:'CSV',accept:{'text/csv':['.csv']}}]}).then(function(handle){\n            self.nHandle=handle;self.nFile=handle.name;\n            self.notes=[];self.nextNid=1;\n            return self.writeNoteCSV();\n        }).then(function(){\n            self.checkReady();\n        }).catch(function(e){if(e.name!=='AbortError')self.showErr(e.message)});\n    },\n\n    writeMemberCSV:function(){\n        if(!this.mHandle)return Promise.resolve();\n        var csv='ID,Member ID,Member Name,Metal Tier,Next Call,Call Type,CM\\n';\n        this.members.forEach(function(m){csv+=csvF(m.id)+','+csvF(m.memberId)+','+csvF(m.name)+','+csvF(m.tier)+','+csvF(m.nextCall)+','+csvF(m.callType)+','+csvF(m.cm)+'\\n'});\n        var handle=this.mHandle;\n        return handle.createWritable().then(function(w){return w.write(csv).then(function(){return w.close()})});\n    },\n\n    writeNoteCSV:function(){\n        if(!this.nHandle)return Promise.resolve();\n        var csv='Note ID,Member ID,Timestamp,Note\\n';\n        this.notes.forEach(function(n){csv+=csvF(n.id)+','+csvF(n.memberId)+','+csvF(n.ts)+','+csvF(n.note)+'\\n'});\n        var handle=this.nHandle;\n        return handle.createWritable().then(function(w){return w.write(csv).then(function(){return w.close()})});\n    },\n\n    showErr:function(msg){\n        var el=document.getElementById('setupErr');\n        el.textContent='Error: '+msg;\n        el.style.display='block';\n    },\n\n    checkReady:function(){\n        var ms=document.getElementById('setupMStatus'),ns=document.getElementById('setupNStatus');\n        var mc=document.getElementById('setupM'),nc=document.getElementById('setupN');\n        if(this.mHandle){mc.classList.add('done');ms.className='setup-status ok';ms.innerHTML='<span class=\"dot\"></span> '+this.esc(this.mFile)}\n        if(this.nHandle){nc.classList.add('done');ns.className='setup-status ok';ns.innerHTML='<span class=\"dot\"></span> '+this.esc(this.nFile)}\n        if(this.mHandle&&this.nHandle){\n            var self=this;\n            setTimeout(function(){\n                document.getElementById('setup').style.display='none';\n                document.getElementById('app').style.display='block';\n                document.getElementById('badgeM').textContent=self.mFile;\n                document.getElementById('badgeN').textContent=self.nFile;\n                self.render();\n                self.toast('Ready — changes auto-save to CSV','success');\n            },300);\n        }\n    },\n\n    /* ===== PARSE ===== */\n    parseMemberCSV:function(text){\n        var rows=parseCSV(text);if(!rows.length)return;\n        var first=rows[0].map(function(x){return x.trim().toLowerCase()});\n        var hasH=first.some(function(x){return x==='member id'||x==='member name'});\n        var data=hasH?rows.slice(1):rows;\n        this.members=[];var self=this;\n        data.forEach(function(r){if(!r.some(function(x){return x.trim()}))return;self.members.push({id:(r[0]||'').trim(),memberId:(r[1]||'').trim(),name:(r[2]||'').trim(),tier:(r[3]||'').trim(),nextCall:(r[4]||'').trim(),callType:(r[5]||'').trim(),cm:(r[6]||'').trim()})});\n        var mx=0;this.members.forEach(function(m){var n=parseInt(m.id);if(!isNaN(n)&&n>mx)mx=n});this.nextMid=mx+1;\n    },\n    parseNoteCSV:function(text){\n        var rows=parseCSV(text);if(!rows.length)return;\n        var first=rows[0].map(function(x){return x.trim().toLowerCase()});\n        var hasH=first.some(function(x){return x==='note id'||x==='timestamp'});\n        var data=hasH?rows.slice(1):rows;\n        this.notes=[];var self=this;\n        data.forEach(function(r){if(!r.some(function(x){return x.trim()}))return;self.notes.push({id:(r[0]||'').trim(),memberId:(r[1]||'').trim(),ts:(r[2]||'').trim(),note:(r[3]||'').trim()})});\n        var mx=0;this.notes.forEach(function(n){var v=parseInt(n.id);if(!isNaN(v)&&v>mx)mx=v});this.nextNid=mx+1;\n    },\n\n    /* ===== MEMBER CRUD (auto-saves to CSV) ===== */\n    addMember:function(data){\n        data.id=String(this.nextMid++);\n        this.members.push(data);\n        this.writeMemberCSV();\n        this.render();this.toast('Member added & saved','success');\n    },\n    updateMember:function(id,data){\n        var i=this.members.findIndex(function(m){return m.id===id});\n        if(i!==-1){this.members[i]=Object.assign({},this.members[i],data);this.writeMemberCSV();this.render();this.toast('Updated & saved','success')}\n    },\n    removeMember:function(id){\n        this.members=this.members.filter(function(m){return m.id!==id});\n        this.notes=this.notes.filter(function(n){return n.memberId!==id});\n        this.writeMemberCSV();this.writeNoteCSV();\n        this.render();this.toast('Deleted & saved','danger');\n    },\n\n    /* ===== NOTE CRUD (auto-saves to CSV) ===== */\n    addNote:function(){\n        if(!this.notesForId)return;\n        var ta=document.getElementById('noteInput');\n        var text=ta.value.trim();\n        if(!text){this.toast('Note is empty','danger');return}\n        this.notes.push({id:String(this.nextNid++),memberId:this.notesForId,ts:new Date().toISOString(),note:text});\n        ta.value='';\n        this.writeNoteCSV();\n        this.renderNotesList();this.render();this.toast('Note added & saved','success');\n    },\n    editNote:function(nid){\n        var card=document.getElementById('nc-'+nid);if(!card)return;\n        var n=this.notes.find(function(x){return x.id===nid});if(!n)return;\n        // Replace header buttons with Save/Cancel\n        var head=card.querySelector('.note-head');\n        head.innerHTML='<span class=\"note-time\">'+this.fmtTime(n.ts)+'</span><div><button class=\"btn btn-sm btn-p\" onclick=\"App.saveEditNote(\\''+nid+'\\')\">Save</button> <button class=\"btn btn-sm\" onclick=\"App.renderNotesList()\">Cancel</button></div>';\n        // Replace text with full textarea\n        var wrap=card.querySelector('.note-text-wrap');\n        wrap.innerHTML='<textarea class=\"note-edit-ta\" id=\"nedit-'+nid+'\" style=\"height:100%\">'+this.esc(n.note).replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>')+'</textarea>';\n        document.getElementById('nedit-'+nid).focus();\n    },\n    saveEditNote:function(nid){\n        var ta=document.getElementById('nedit-'+nid);if(!ta)return;\n        var text=ta.value.trim();if(!text){this.toast('Note is empty','danger');return}\n        var i=this.notes.findIndex(function(x){return x.id===nid});\n        if(i!==-1){this.notes[i].note=text;this.writeNoteCSV();this.renderNotesList();this.toast('Note updated','success')}\n    },\n    deleteNote:function(nid){\n        if(!confirm('Delete this note?'))return;\n        this.notes=this.notes.filter(function(n){return n.id!==nid});\n        this.writeNoteCSV();\n        this.renderNotesList();this.render();\n    },\n    getNotesFor:function(mid){return this.notes.filter(function(n){return n.memberId===mid}).sort(function(a,b){return new Date(b.ts)-new Date(a.ts)})},\n\n    /* ===== SORT / SEARCH ===== */\n    sort:function(col){\n        if(this.sortCol===col)this.sortDir=this.sortDir==='asc'?'desc':'asc';\n        else{this.sortCol=col;this.sortDir='asc'}\n        this.manualSort=true;\n        this.render();\n    },\n    onSearch:function(v){this.query=v;this.render()},\n    filtered:function(){\n        var self=this,list=this.members.slice();\n        if(this.query){var q=this.query.toLowerCase();list=list.filter(function(m){return m.id.toLowerCase().indexOf(q)>-1||m.name.toLowerCase().indexOf(q)>-1||m.tier.toLowerCase().indexOf(q)>-1||m.nextCall.toLowerCase().indexOf(q)>-1||m.callType.toLowerCase().indexOf(q)>-1})}\n\n        if(!this.manualSort){\n            // Default: date ascending first, then call type priority\n            list.sort(function(a,b){\n                var da=a.nextCall||'9999',db=b.nextCall||'9999';\n                if(da<db)return -1;if(da>db)return 1;\n                var ca=CP[a.callType]!=null?CP[a.callType]:99;\n                var cb=CP[b.callType]!=null?CP[b.callType]:99;\n                return ca-cb;\n            });\n        }else{\n            var dir=this.sortDir==='asc'?1:-1,col=this.sortCol;\n            list.sort(function(a,b){\n                var av,bv;\n                if(col==='id'){av=parseInt(a.id)||0;bv=parseInt(b.id)||0}\n                else if(col==='callType'){av=CP[a.callType]!=null?CP[a.callType]:99;bv=CP[b.callType]!=null?CP[b.callType]:99}\n                else if(col==='tier'){av=TIER_ORDER[a.tier]!=null?TIER_ORDER[a.tier]:99;bv=TIER_ORDER[b.tier]!=null?TIER_ORDER[b.tier]:99}\n                else{av=(a[col]||'').toLowerCase();bv=(b[col]||'').toLowerCase()}\n                return av<bv?-dir:av>bv?dir:0;\n            });\n        }\n        return list;\n    },\n\n    /* ===== RENDER ===== */\n    render:function(){\n        var list=this.filtered(),self=this;\n        var tbody=document.getElementById('tbody'),empty=document.getElementById('emptyState'),table=document.getElementById('dataTable'),stats=document.getElementById('stats');\n        stats.innerHTML='<b>'+this.members.length+'</b> member'+(this.members.length!==1?'s':'');\n        document.querySelectorAll('th[data-col]').forEach(function(th){\n            var c=th.dataset.col;th.classList.toggle('sorted',c===self.sortCol);\n            var s=th.querySelector('.si');if(s)s.textContent=c===self.sortCol?(self.sortDir==='asc'?'\\u25B2':'\\u25BC'):'\\u25B2';\n        });\n        if(!list.length){table.style.display='none';empty.style.display='block';\n            empty.querySelector('h3').textContent=this.query?'No matches':'No members yet';\n            empty.querySelector('p').textContent=this.query?'Try a different search.':'Click \"+ Add Member\" to get started.';\n        }else{\n            table.style.display='';empty.style.display='none';\n            tbody.innerHTML=list.map(function(m){\n                var tc='tier-'+(m.tier||'').toLowerCase();\n                var nc=self.getNotesFor(m.id).length;\n                var isUrg=m.callType==='Urgent';\n                return '<tr onclick=\"App.rowClick(event,\\''+m.id+'\\')\">'\n                    +'<td class=\"cell-id\">'+self.esc(m.memberId)+' <button class=\"copy-btn\" onclick=\"event.stopPropagation();App.copyText(\\''+self.esc(m.memberId)+'\\')\" title=\"Copy Member ID\">&#9112;</button></td>'\n                    +'<td class=\"cell-name\">'+self.esc(m.name)+'</td>'\n                    +'<td><span class=\"tier '+tc+'\">'+self.esc(m.tier)+'</span></td>'\n                    +'<td>'+self.esc(m.nextCall)+'</td>'\n                    +'<td'+(isUrg?' class=\"cell-urgent\"':'')+'>'+self.esc(m.callType)+'</td>'\n                    +'<td>'+self.esc(m.cm||'')+'</td>'\n                    +'<td><span class=\"nc'+(nc?' has':'')+'\">'+(nc||'0')+' note'+(nc!==1?'s':'')+'</span></td>'\n                    +'<td class=\"cell-actions\">'\n                    +'<button class=\"btn btn-sm\" onclick=\"event.stopPropagation();App.showMemberModal(\\''+m.id+'\\')\">Edit</button> '\n                    +'<button class=\"btn btn-sm btn-d\" onclick=\"event.stopPropagation();App.showDeleteModal(\\''+m.id+'\\')\">Del</button>'\n                    +'</td></tr>';\n            }).join('');\n        }\n    },\n    esc:function(s){if(s==null)return'';var d=document.createElement('div');d.textContent=String(s);return d.innerHTML},\n    fmtTime:function(iso){try{var d=new Date(iso);return d.toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'})+' at '+d.toLocaleTimeString('en-US',{hour:'numeric',minute:'2-digit'})}catch(e){return iso}},\n    rowClick:function(e,id){if(e.target.closest('button'))return;this.showNotesModal(id)},\n    lockScroll:function(){document.body.classList.add('no-scroll')},\n    unlockScroll:function(){document.body.classList.remove('no-scroll')},\n\n    /* ===== MODALS ===== */\n    showMemberModal:function(id){\n        this.editId=id||null;\n        document.getElementById('mmTitle').textContent=id?'Edit Member':'Add Member';\n        if(id){var m=this.members.find(function(x){return x.id===id});if(!m)return;\n            document.getElementById('fMemberId').value=m.memberId;document.getElementById('fName').value=m.name;\n            document.getElementById('fTier').value=m.tier;document.getElementById('fCallType').value=m.callType;\n            document.getElementById('fCM').value=m.cm||'';document.getElementById('fNextCall').value=m.nextCall;\n        }else{document.getElementById('mForm').reset();document.getElementById('fNextCall').value=new Date().toISOString().split('T')[0]}\n        document.getElementById('memberModal').classList.add('open');this.lockScroll();\n        setTimeout(function(){document.getElementById('fMemberId').focus()},50);\n    },\n    hideMemberModal:function(){document.getElementById('memberModal').classList.remove('open');this.unlockScroll();this.editId=null},\n    submitMember:function(e){\n        if(e)e.preventDefault();\n        var memberId=document.getElementById('fMemberId').value.trim();\n        var name=document.getElementById('fName').value.trim();\n        var tier=document.getElementById('fTier').value;\n        var ct=document.getElementById('fCallType').value;\n        if(!memberId){this.toast('Member ID required','danger');return false}\n        if(!name){this.toast('Name required','danger');return false}\n        if(!ct){this.toast('Select call type','danger');return false}\n        var cm=document.getElementById('fCM').value.trim();\n        var data={memberId:memberId,name:name,tier:tier,callType:ct,nextCall:document.getElementById('fNextCall').value,cm:cm};\n        if(this.editId)this.updateMember(this.editId,data);else this.addMember(data);\n        this.hideMemberModal();return false;\n    },\n    showNotesModal:function(id){\n        this.notesForId=id;\n        var m=this.members.find(function(x){return x.id===id});if(!m)return;\n        document.getElementById('notesSub').textContent=' \\u2014 '+m.name;\n        document.getElementById('noteInfo').innerHTML='<div><strong>'+this.esc(m.name)+'</strong> &middot; <span class=\"tier tier-'+m.tier.toLowerCase()+'\" style=\"font-size:10px;padding:1px 7px\">'+this.esc(m.tier)+'</span>'+(m.cm?' &middot; <span style=\"color:var(--t2);font-size:12px\">CM: '+this.esc(m.cm)+'</span>':'')+'</div><div class=\"nid\"><span id=\"nidText\">'+this.esc(m.memberId)+'</span> <button class=\"copy-btn\" onclick=\"App.copyId()\" title=\"Copy Member ID\">&#9112;</button></div>';\n        // Editable fields\n        var opts=CALL_TYPES.map(function(t){return '<option'+(t===m.callType?' selected':'')+'>'+t+'</option>'}).join('');\n        document.getElementById('noteFields').innerHTML='<div class=\"nf-group\"><label>Next Call</label><input type=\"date\" id=\"nfNextCall\" value=\"'+this.esc(m.nextCall)+'\" onchange=\"App.updateFromNotes()\"></div><div class=\"nf-group\"><label>Call Type</label><select id=\"nfCallType\" onchange=\"App.updateFromNotes()\"><option value=\"\">Select...</option>'+opts+'</select></div>';\n        document.getElementById('noteInput').value='';\n        this.renderNotesList();\n        document.getElementById('notesModal').classList.add('open');this.lockScroll();\n        setTimeout(function(){document.getElementById('noteInput').focus()},50);\n    },\n    updateFromNotes:function(){\n        if(!this.notesForId)return;\n        var nc=document.getElementById('nfNextCall').value;\n        var ct=document.getElementById('nfCallType').value;\n        this.updateMember(this.notesForId,{nextCall:nc,callType:ct});\n    },\n    hideNotesModal:function(){document.getElementById('notesModal').classList.remove('open');this.unlockScroll();this.notesForId=null},\n    renderNotesList:function(){\n        var list=this.getNotesFor(this.notesForId),self=this;\n        var el=document.getElementById('notesList');\n        if(!list.length){el.innerHTML='<div class=\"notes-empty\">No notes yet.<br>Write one on the left.</div>';return}\n        el.innerHTML=list.map(function(n){return '<div class=\"note-card\" id=\"nc-'+n.id+'\"><div class=\"note-head\"><span class=\"note-time\">'+self.fmtTime(n.ts)+'</span><div><button class=\"note-edit\" onclick=\"App.editNote(\\''+n.id+'\\')\" title=\"Edit\">&#9998;</button> <button class=\"note-del\" onclick=\"App.deleteNote(\\''+n.id+'\\')\" title=\"Delete\">&times;</button></div></div><div class=\"note-text-wrap\"><div class=\"note-text\">'+self.esc(n.note)+'</div></div></div>'}).join('');\n    },\n    showDeleteModal:function(id){this.delId=id;var m=this.members.find(function(x){return x.id===id});document.getElementById('delName').textContent=m?m.name:'this member';document.getElementById('deleteModal').classList.add('open');this.lockScroll()},\n    hideDeleteModal:function(){document.getElementById('deleteModal').classList.remove('open');this.unlockScroll();this.delId=null},\n    confirmDelete:function(){if(this.delId){this.removeMember(this.delId);this.hideDeleteModal()}},\n\n    /* ===== IMPORT ===== */\n    importRows:null,importCols:null,\n    handleImportFile:function(input){\n        var file=input.files[0];if(!file)return;\n        var self=this;\n        var reader=new FileReader();\n        reader.onload=function(e){\n            var rows=parseCSV(e.target.result);\n            if(rows.length<2){self.toast('CSV is empty','danger');return}\n            self.importCols=rows[0].map(function(c){return c.trim()});\n            self.importRows=rows.slice(1).filter(function(r){return r.some(function(x){return x.trim()})});\n            self.showImportModal();\n        };\n        reader.readAsText(file);\n        input.value='';\n    },\n    showImportModal:function(){\n        var cols=this.importCols;\n        var fields=[{key:'memberId',label:'Member ID',hints:['member id','memberid','id','hicn','member_id','subscriber']},{key:'name',label:'Member Name',hints:['member name','name','member','full name','patient','patient name']},{key:'tier',label:'Metal Tier',hints:['metal tier','tier','metal','plan tier','plan']},{key:'cm',label:'CM',hints:['cm','care manager','case manager']}];\n        var html='';\n        var self=this;\n        fields.forEach(function(f){\n            var best=-1;\n            cols.forEach(function(c,i){\n                var cl=c.toLowerCase();\n                if(best===-1&&f.hints.some(function(h){return cl.indexOf(h)>-1}))best=i;\n            });\n            var opts='<option value=\"-1\">-- Skip --</option>';\n            cols.forEach(function(c,i){opts+='<option value=\"'+i+'\"'+(i===best?' selected':'')+'>'+self.esc(c)+'</option>'});\n            html+='<div class=\"fi\"><label>'+f.label+'</label><select id=\"imp_'+f.key+'\">'+opts+'</select></div>';\n        });\n        document.getElementById('importMappings').innerHTML=html;\n        document.getElementById('importFilters').innerHTML='<div style=\"color:var(--t3);font-size:12px\">No filters — all rows will be imported</div>';\n        this.importFilterCount=0;\n        document.getElementById('importNextCall').value=new Date().toISOString().split('T')[0];\n        document.getElementById('importCallType').value='';\n        this.updateImportCount();\n        document.getElementById('importModal').classList.add('open');\n        this.lockScroll();\n    },\n    importFilterCount:0,\n    addImportFilter:function(){\n        var cols=this.importCols,self=this;\n        var container=document.getElementById('importFilters');\n        // Clear the \"no filters\" message on first add\n        if(this.importFilterCount===0)container.innerHTML='';\n        var fid='impf_'+(this.importFilterCount++);\n        var div=document.createElement('div');div.className='filter-row';div.id=fid;\n        var opts='<option value=\"-1\">Select column...</option>';\n        cols.forEach(function(c,i){opts+='<option value=\"'+i+'\">'+self.esc(c)+'</option>'});\n        div.innerHTML='<div class=\"filter-header\"><select onchange=\"App.populateFilterChips(\\''+fid+'\\',this.value)\">'+opts+'</select><button class=\"filter-remove\" onclick=\"App.removeImportFilter(\\''+fid+'\\')\">&times;</button></div><div class=\"filter-chips\"></div>';\n        container.appendChild(div);\n    },\n    removeImportFilter:function(fid){\n        var el=document.getElementById(fid);if(el)el.remove();\n        var container=document.getElementById('importFilters');\n        if(!container.children.length){container.innerHTML='<div style=\"color:var(--t3);font-size:12px\">No filters — all rows will be imported</div>';this.importFilterCount=0}\n        this.updateImportCount();\n    },\n    populateFilterChips:function(fid,colIdx){\n        colIdx=parseInt(colIdx);\n        var chips=document.querySelector('#'+fid+' .filter-chips');\n        if(colIdx===-1){chips.innerHTML='';this.updateImportCount();return}\n        var vals={},self=this;\n        this.importRows.forEach(function(r){var v=(r[colIdx]||'').trim();if(v)vals[v]=(vals[v]||0)+1});\n        var sorted=Object.keys(vals).sort();\n        chips.innerHTML=sorted.map(function(v){\n            return '<label class=\"fchip\"><input type=\"checkbox\" value=\"'+self.esc(v)+'\" onchange=\"this.parentElement.classList.toggle(\\'on\\',this.checked);App.updateImportCount()\"> '+self.esc(v)+' <span style=\"opacity:.5\">('+vals[v]+')</span></label>';\n        }).join('');\n        this.updateImportCount();\n    },\n    getImportFilteredRows:function(){\n        var rows=this.importRows;\n        var filterRows=document.querySelectorAll('.filter-row');\n        filterRows.forEach(function(fr){\n            var sel=fr.querySelector('select');\n            var colIdx=parseInt(sel.value);\n            if(colIdx===-1)return;\n            var checks=fr.querySelectorAll('input:checked');\n            if(!checks.length)return; // no values checked = no filter on this column\n            var allowed={};\n            checks.forEach(function(cb){allowed[cb.value]=true});\n            rows=rows.filter(function(r){return allowed[(r[colIdx]||'').trim()]});\n        });\n        return rows;\n    },\n    updateImportCount:function(){\n        var rows=this.getImportFilteredRows();\n        document.getElementById('importPreview').textContent=rows.length+' of '+this.importRows.length+' rows will be imported';\n    },\n    hideImportModal:function(){document.getElementById('importModal').classList.remove('open');this.unlockScroll()},\n    runImport:function(){\n        var midIdx=parseInt(document.getElementById('imp_memberId').value);\n        var nameIdx=parseInt(document.getElementById('imp_name').value);\n        var tierIdx=parseInt(document.getElementById('imp_tier').value);\n        var cmIdx=parseInt(document.getElementById('imp_cm').value);\n        var callType=document.getElementById('importCallType').value;\n        var nextCall=document.getElementById('importNextCall').value;\n        if(!callType){this.toast('Select a default Call Type','danger');return}\n        if(midIdx===-1&&nameIdx===-1){this.toast('Map at least Member ID or Name','danger');return}\n        var added=0,updated=0,skipped=0,self=this;\n        var filteredRows=this.getImportFilteredRows();\n        filteredRows.forEach(function(row){\n            var mid=midIdx>=0?(row[midIdx]||'').trim():'';\n            var name=nameIdx>=0?(row[nameIdx]||'').trim():'';\n            var tier=tierIdx>=0?(row[tierIdx]||'').trim():'';\n            var cm=cmIdx>=0?(row[cmIdx]||'').trim():'';\n            if(!mid&&!name){skipped++;return}\n            // If Member ID already exists, update their fields\n            var existing=mid?self.members.findIndex(function(m){return m.memberId===mid}):-1;\n            if(existing!==-1){\n                self.members[existing].tier=tier||self.members[existing].tier;\n                self.members[existing].nextCall=nextCall;\n                self.members[existing].callType=callType;\n                self.members[existing].cm=cm||self.members[existing].cm;\n                if(name)self.members[existing].name=name;\n                updated++;return;\n            }\n            self.members.push({\n                id:String(self.nextMid++),\n                memberId:mid,\n                name:name,\n                tier:tier||'',\n                nextCall:nextCall,\n                callType:callType,\n                cm:cm||''\n            });\n            added++;\n        });\n        this.writeMemberCSV();\n        this.render();\n        this.hideImportModal();\n        var msg=added+' added';if(updated)msg+=', '+updated+' updated';if(skipped)msg+=', '+skipped+' skipped';\n        this.toast(msg,'success');\n    },\n\n    copyId:function(){var id=document.getElementById('nidText').textContent;navigator.clipboard.writeText(id).then(function(){App.toast('Copied '+id,'success')}).catch(function(){App.toast('Copy failed','danger')})},\n    copyText:function(text){navigator.clipboard.writeText(text).then(function(){App.toast('Copied '+text,'success')}).catch(function(){App.toast('Copy failed','danger')})},\n    toast:function(msg,type){var el=document.createElement('div');el.className='toast toast-'+(type||'info');el.textContent=msg;document.getElementById('toasts').appendChild(el);setTimeout(function(){el.classList.add('out');setTimeout(function(){el.remove()},200)},2500)},\n\n    bindDrop:function(){\n        var self=this;\n        var zone=document.getElementById('dropZone');\n        if(!zone)return;\n        zone.addEventListener('dragover',function(e){e.preventDefault();zone.classList.add('over')});\n        zone.addEventListener('dragleave',function(){zone.classList.remove('over')});\n        zone.addEventListener('drop',function(e){\n            e.preventDefault();zone.classList.remove('over');\n            var files=Array.prototype.slice.call(e.dataTransfer.files).filter(function(f){return f.name.toLowerCase().endsWith('.csv')});\n            if(!files.length){self.toast('No CSV files found','danger');return}\n            // Match by stored filename or by content headers\n            files.forEach(function(file){\n                var name=file.name.toLowerCase();\n                var reader=new FileReader();\n                reader.onload=function(ev){\n                    var text=ev.target.result;\n                    var firstLine=(text.split('\\n')[0]||'').toLowerCase();\n                    var isNotes=name.indexOf('note')>-1||firstLine.indexOf('note id')>-1||firstLine.indexOf('timestamp')>-1;\n                    if(!isNotes&&self.mHandle)isNotes=true; // already have members, this must be notes\n\n                    if(isNotes&&!self.nHandle){\n                        // Need a write handle — prompt for it pointing to this file\n                        self.parseNoteCSV(text);\n                        self.nFile=file.name;\n                        // Get write handle via showSaveFilePicker\n                        window.showSaveFilePicker({suggestedName:file.name,types:[{description:'CSV',accept:{'text/csv':['.csv']}}]}).then(function(h){\n                            self.nHandle=h;\n                            return self.writeNoteCSV();\n                        }).then(function(){self.checkReady()}).catch(function(err){\n                            if(err.name!=='AbortError')self.showErr(err.message);\n                        });\n                    }else if(!self.mHandle){\n                        self.parseMemberCSV(text);\n                        self.mFile=file.name;\n                        window.showSaveFilePicker({suggestedName:file.name,types:[{description:'CSV',accept:{'text/csv':['.csv']}}]}).then(function(h){\n                            self.mHandle=h;\n                            return self.writeMemberCSV();\n                        }).then(function(){self.checkReady()}).catch(function(err){\n                            if(err.name!=='AbortError')self.showErr(err.message);\n                        });\n                    }\n                };\n                reader.readAsText(file);\n            });\n        });\n        // Prevent default on body so drops work\n        document.body.addEventListener('dragover',function(e){e.preventDefault()});\n    },\n\n    bindKeys:function(){\n        var self=this;\n        document.addEventListener('keydown',function(e){\n            if(e.key==='Escape'){\n                if(document.getElementById('deleteModal').classList.contains('open'))self.hideDeleteModal();\n                else if(document.getElementById('notesModal').classList.contains('open'))self.hideNotesModal();\n                else if(document.getElementById('memberModal').classList.contains('open'))self.hideMemberModal();\n            }\n            if(e.ctrlKey&&e.key==='n'&&!document.querySelector('.mo.open')){e.preventDefault();if(self.mHandle&&self.nHandle)self.showMemberModal()}\n        });\n    }\n};\n\nApp.init();\n</script>\n</body>\n</html>\n";
